using System;
using System.Data.SqlClient;
using System.Threading.Tasks;

public class DatabaseHelper
{
    private static readonly string ConnectionString = "Server=localhost;Database=HackathonDB;User Id=sa;Password=" + GetPasswordFromEnvironment() + ";";

    private static string GetPasswordFromEnvironment()
    {
        var password = Environment.GetEnvironmentVariable("DB_PASSWORD");
        if (string.IsNullOrEmpty(password))
        {
            throw new InvalidOperationException("Database password not found in environment variables. Please set DB_PASSWORD environment variable.");
        }
        return password;
    }

    public static async Task<SqlConnection> GetConnectionAsync()
    {
        var connection = new SqlConnection(ConnectionString);
        await connection.OpenAsync();
        return connection;
    }

    public static SqlConnection GetConnection()
    {
        var connection = new SqlConnection(ConnectionString);
        connection.Open();
        return connection;
    }
}